class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: GetEnvironmentVariable returns null for empty
        // values on non-Windows platforms. Use DoesEnvironmentVariableExist to
        // distinguish "not set" from "set to empty".
        if (!Environment.DoesEnvironmentVariableExist("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

